mapper.select:
SELECT A.USERID , A.CNTR_MOBILE_NO , A.SYS_RDATE , B.SVC_CNTR_NO , B.CONTRACT_NUM , A.REP_NO , B.CUSTOMER_ID AS CUST_ID , B.MODEL_NAME , B.MODEL_ID , B.SUB_STATUS , A.CNTR_MOBILE_NO AS unSvcNo , B.USER_SSN AS unUserSSn , (SELECT CUSTOMER_TYPE FROM MSP_JUO_CUS_INFO@DL_MSP WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS CSTMR_TYPE , (SELECT CUSTOMER_LINK_NAME FROM MSP_JUO_CUS_INFO@DL_MSP WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS userName , B.OPEN_AGNT_CD , B.LST_COM_ACTV_DATE , B.PPPO FROM MCP_USER_CNTR_MNG A, MSP_JUO_SUB_INFO@DL_MSP B WHERE UPPER(A.USERID) = UPPER(#{userId}) AND A.SVC_CNTR_NO = B.CONTRACT_NUM
AND A.CUSTOMER_ID = #{customerId}
AND B.SUB_STATUS <> 'C' ORDER BY A.REP_NO ASC

SELECT CONTRACT_NUM , SVC_CNTR_NO , T1.SUBSCRIBER_NO , T1.USER_SSN , T1.SUB_LINK_NAME , T2.BL_BILLING_METHOD , T2.BAN , T2.BAN_ADR_ZIP , T2.BAN_ADR_PRIMARY_LN , T2.BAN_ADR_SECONDARY_LN , T1.CUSTOMER_ID , T1.SUB_STATUS , T3.CUSTOMER_TYPE FROM MSP_JUO_SUB_INFO@DL_MSP T1 , MSP_JUO_BAN_INFO@DL_MSP T2 , MSP_JUO_CUS_INFO@DL_MSP T3 WHERE 1=1 AND T1.BAN = T2.BAN AND T1.CUSTOMER_ID = T3.CUSTOMER_ID AND SUB_STATUS <> 'C'
AND SUBSCRIBER_NO= TRIM(#{mobileNo})
AND UPPER(REPLACE(SUB_LINK_NAME,' ','')) = UPPER(REPLACE(#{name},' ',''))
AND CONTRACT_NUM = #{contractNum}
AND T1.CUSTOMER_ID = #{customerId}

SELECT
AA.SVC_CNTR_NO , AA.SOC , AA.ENGG_MNTH_CNT , AA.RATE_NM , AA.BASE_AMT , AA.RMK , AA.MODEL_NAME , AA.DOBYYYYMMDD , AA.INTM_SRL_NO , AA.MODEL_ID , NVL(AA.DC_AMT, 0) DC_AMT , POINT_ID , AA.SUB_LINK_NAME FROM ( SELECT D.SVC_CNTR_NO , D.CONTRACT_NUM , B.SOC , NVL((SELECT ENGG_MNTH_CNT FROM (SELECT ENGG_MNTH_CNT , ROW_NUMBER() OVER (ORDER BY EVNT_TRTM_DT DESC) AS RNUM FROM MSP_JUO_ADD_INFO@DL_MSP WHERE CONTRACT_NUM = #{svcCntrNo} AND ENGG_MNTH_CNT IS NOT NULL AND APP_END_DATE > TO_CHAR (SYSDATE, 'YYYYMMDDHH24MISS') )WHERE RNUM = 1 ), 0) AS ENGG_MNTH_CNT , C.RATE_NM , C.BASE_AMT , C.RMK , D.MODEL_NAME , D.DOBYYYYMMDD , D.USER_SSN , D.INTM_SRL_NO , D.MODEL_ID , '' AS POINT_ID , 0 AS DC_AMT , D.SUB_LINK_NAME FROM MSP_JUO_FEATURE_INFO@DL_MSP B , MSP_RATE_MST@DL_MSP C , MSP_JUO_SUB_INFO@DL_MSP D WHERE 1=1 AND D.SVC_CNTR_NO = #{svcCntrNo} AND D.CONTRACT_NUM = B.CONTRACT_NUM AND B.SERVICE_TYPE = 'P' AND B.EXPIRATION_DATE > TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') AND B.SOC = C.RATE_CD
) AA

mapper.update:
MERGE INTO  MSP_SOCFAIL_PROC_MST@DL_MSP
USING   DUAL
ON      (CONTRACT_NUM = #{contractNum} AND PRCS_MDL_IND = #{prcsMdlInd})
WHEN MATCHED THEN
    UPDATE SET
        SYS_RDATE = SYSDATE
    WHEN NOT MATCHED THEN
        INSERT (
            CONTRACT_NUM             --계약번호
            , PRCS_MDL_IND             --처리 모듈 구분
            , A_SOC_CODE               --이전 코드 값
            , T_SOC_CODE               --이후 코드 값
            , A_SOC_AMNT               --변경전 요금제 할인 월정액
            , T_SOC_AMNT               --변경후 요금제 할인 월정액
            , SUCC_YN                  --성공여부  ==> 성공시 : Y , 실패시 : N
            , CHG_TYPE                 --(즉시 : I , 예약 : R)
            , SYS_RDATE                --등록일시
            , PROC_MEMO                --처리메모
            , PROC_YN                  --처리여부
            , PROC_ID                  --처리자

            , PROC_DATE                --처리날짜

        ) VALUES (
            #{contractNum}
            , #{prcsMdlInd}
            , #{aSocCode}
            , #{tSocCode}
            , #{aSocAmnt}
            , #{tSocAmnt}
            , #{succYn}
            , #{chgType}
            , SYSDATE
            , #{procMemo}
            , #{procYn}
            , #{procId}

            , #{procDate}

        )

mapper.select:
SELECT COUNT(*)
FROM MCP_SELF_USIM_CHG
WHERE PRGR_STAT_CD = #{eventCd}
  AND MVNO_ORD_NO = #{mvnoOrdNo}
  AND RSLT_CD = #{rsltCd}

/*Mypage.selectCntrListNmChg 현재요금제정보 가져오기 (명의변경) */ SELECT A.USERID , A.CNTR_MOBILE_NO , A.SYS_RDATE , B.SVC_CNTR_NO , B.CONTRACT_NUM , A.REP_NO , B.CUSTOMER_ID AS CUST_ID , B.MODEL_NAME , B.MODEL_ID , B.SUB_STATUS , A.CNTR_MOBILE_NO AS unSvcNo , B.USER_SSN AS unUserSSn , C.CSTMR_TYPE , (SELECT CUSTOMER_TYPE FROM MSP_JUO_CUS_INFO@DL_MSP WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS CUSTOMER_TYPE , (SELECT CUSTOMER_LINK_NAME FROM MSP_JUO_CUS_INFO@DL_MSP WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS userName , B.OPEN_AGNT_CD , C.LST_RATE_CD AS SOC , C.LST_RATE_NM AS SOC_NM , NVL((SELECT FREE_DATA_CNT FROM MSP_RATE_MST@DL_MSP WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_DATA_CNT , NVL((SELECT FREE_CALL_CNT FROM MSP_RATE_MST@DL_MSP WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_CALL_CNT , NVL((SELECT FREE_SMS_CNT FROM MSP_RATE_MST@DL_MSP WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_SMS_CNT , B.ON_OFF_TYPE , D.COL_DELINQ_STATUS , D.BAN_ADR_ZIP , D.BAN_ADR_PRIMARY_LN , D.BAN_ADR_SECONDARY_LN FROM MCP_USER_CNTR_MNG A , MSP_JUO_SUB_INFO@DL_MSP B , MSP_REQUEST_DTL@DL_MSP C , MSP_JUO_BAN_INFO@DL_MSP D WHERE UPPER(A.USERID) = UPPER(#{userId}) AND A.SVC_CNTR_NO = B.CONTRACT_NUM AND A.SVC_CNTR_NO = C.CONTRACT_NUM(+) AND B.BAN = D.BAN(+) AND B.SUB_STATUS <> 'C'
AND A.CUSTOMER_ID = #{customerId}
AND B.CONTRACT_NUM = #{contractNum}
ORDER BY A.REP_NO ASC

/*Mypage.pvcCommDataList 통신자료 제공내역 요청리스트 가져오기 */ SELECT ROW_NUMBER() OVER(ORDER BY AA.APY_SEQ DESC) AS RNUM , AA.APY_SEQ , AA.APY_DT --신청일시 , AA.RESULT_YN --처리결과 , AA.IS_INVST_PROC --제공여부 FROM ( SELECT A.APY_SEQ , TO_CHAR(A.APY_DT, 'YYYY.MM.DD') AS APY_DT , DECODE(A.RESULT_YN, 'Y', '처리', 'N', '미처리', '조회 중') AS RESULT_YN , DECODE((SELECT COUNT(*) FROM MSP_INVST_REQ_MST@DL_MSP B, MSP_JUO_CUS_INFO@DL_MSP C WHERE REPLACE(A.TGT_SVC_NO, '-', '') = B.SUBSCRIBER_NO AND A.MYSLF_ATHN_CI = C.SELF_CSTMR_CI AND B.CUSTOMER_ID = C.CUSTOMER_ID AND REQ_TYPE = '10' ), 0, 'N', 'Y') AS IS_INVST_PROC FROM MSP_COMM_DAT_PRV_TXN@DL_MSP A WHERE TO_CHAR(A.PROC_DT, 'YYYYMMDD') BETWEEN TO_CHAR(ADD_MONTHS(SYSDATE, -1), 'YYYYMMDD') AND TO_CHAR(SYSDATE, 'YYYYMMDD') AND A.CONTRACT_NUM = #{contractNum}
UNION ALL
SELECT A.APY_SEQ , TO_CHAR(A.APY_DT, 'YYYY.MM.DD') AS APY_DT , '조회 중' AS RESULT_YN , '' AS IS_INVST_PROC FROM MSP_COMM_DAT_PRV_TXN@DL_MSP A WHERE A.PROC_DT IS NULL AND A.CONTRACT_NUM = #{contractNum} ) AA

/*Mypage.getOrgScanId MSP_JUO_SUB_INFO에서 orgSacnId 조회 */
SELECT SCAN_ID
FROM MSP_JUO_SUB_INFO@DL_MSP
WHERE CONTRACT_NUM = #{contractNum}

mapper.insert:

    SELECT TO_NUMBER(TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(RWD_SEQ.NEXTVAL@DL_MSP, '0000')))  FROM DUAL

INSERT INTO MSP_RWD_ORDER@DL_MSP (
     RWD_SEQ
   , RWD_PROD_CD
   , RES_NO

   , REQUEST_KEY

   , CONTRACT_NUM
   , IF_TRGT_CD
   , CHN_CD
   , IMEI
   , BUY_PRIC
   , FILE_ID
   , FILE_EXT
   , FILE_DIR
   , REGST_ID
   , REGST_DTTM
   , IMEI_TWO
   , RWD_AUTH_INFO
) VALUES (
     #{rwdSeq}
   , #{rwdProdCd}
   , #{resNo}

   , #{requestKey}

   , #{contractNum}
   , #{ifTrgtCd}
   , #{chnCd}
   , #{imei}
   , #{buyPric}
   , #{fileId}
   , UPPER(#{fileExt})
   , #{fileDir}
   , #{regstId}
   , SYSDATE
   , #{imeiTwo}
   , #{rwdAuthInfo}
)

mapper.select:
SELECT COUNT(RWD_SEQ) AS CNT
FROM MSP_RWD_ORDER@DL_MSP
WHERE RES_NO= #{resNo}
AND IF_TRGT_CD != 'C'

    AND REQUEST_KEY = #{requestKey}

mapper.update:
UPDATE MSP_RWD_ORDER@DL_MSP
SET
     RWD_PROD_CD= #{rwdProdCd}
    ,RES_NO= #{resNo}

    ,REQUEST_KEY= #{requestKey}

    ,CONTRACT_NUM= #{contractNum}
    ,IF_TRGT_CD = #{ifTrgtCd}
    ,CHN_CD = #{chnCd}
    ,IMEI = #{imei}
    ,BUY_PRIC =  #{buyPric}
    ,FILE_ID = #{fileId}
    ,FILE_EXT = UPPER(#{fileExt})
    ,FILE_DIR = #{fileDir}
    ,REGST_ID = #{regstId}
    ,REGST_DTTM = SYSDATE
    ,IMEI_TWO = #{imeiTwo}
    ,RWD_AUTH_INFO = #{rwdAuthInfo}
WHERE RWD_SEQ= #{rwdSeq}

mapper.select:
SELECT RWD_SEQ
FROM (
    SELECT
        ROW_NUMBER() OVER (ORDER BY REGST_DTTM DESC) AS ROW_NUM,
        RWD_SEQ
    FROM MSP_RWD_ORDER@DL_MSP
    WHERE RES_NO= #{resNo}

    AND REQUEST_KEY = #{requestKey}

)
WHERE ROW_NUM = 1

SELECT CUSTOMER_LINK_NAME AS SUB_LINK_NAME , CUSTOMER_SSN AS USER_SSN
FROM MSP_JUO_CUS_INFO@DL_MSP
WHERE CUSTOMER_ID = #{customerId}
